// Helper types and events between CacheNode and StorageProxy
type tQElem = (src: machine, key: int, value: int, isWrite: bool, podId: int, rid: int);
type tWriteItem = (client: machine, value: int);

// Requests from CacheNode to StorageProxy
event eProxyReadReq: (src: machine, key: int, podId: int, rid: int);
event eProxyWriteReq: (src: machine, key: int, value: int, podId: int, rid: int);

// Responses from StorageProxy to CacheNode
event eProxyReadResp: (rid: int, key: int, value: int);
event eProxyWriteResp: (rid: int, key: int, success: bool, value: int);

// StorageProxy models a network proxy with a queue and nondeterministic forwarding/holding.
machine StorageProxy {
    var db: machine;
    var queue: seq[tQElem];
    var hasInflight: bool;
    var inflight: tQElem;

    start state Init {
        entry (p: (db: machine)) {
            db = p.db;
            queue = default(seq[tQElem]);
            hasInflight = false;
            inflight = default(tQElem);
            goto Ready;
        }
    }

    state Ready {
        on eProxyReadReq do (req: (src: machine, key: int, podId: int, rid: int)) {
            var elem: tQElem;
            elem = (src = req.src, key = req.key, value = 0, isWrite = false, podId = req.podId, rid = req.rid);
            queue += (sizeof(queue), elem);
            announce eMonitorProxyEnqueue, (key = req.key, podId = req.podId, isWrite = false);
            TryProgress();
        }

        on eProxyWriteReq do (req: (src: machine, key: int, value: int, podId: int, rid: int)) {
            var elem: tQElem;
            elem = (src = req.src, key = req.key, value = req.value, isWrite = true, podId = req.podId, rid = req.rid);
            queue += (sizeof(queue), elem);
            announce eMonitorProxyEnqueue, (key = req.key, podId = req.podId, isWrite = true);
            TryProgress();
        }

        on eStorageReadResp do (resp: (key: int, value: int)) {
            var r: (rid: int, key: int, value: int);
            // Deliver response to original caller
            announce eMonitorProxyResponseDelivered, (key = resp.key, podId = inflight.podId, isWrite = false);
            r = (rid = inflight.rid, key = resp.key, value = resp.value);
            send inflight.src, eProxyReadResp, r;
            hasInflight = false;
            inflight = default(tQElem);
            TryProgress();
        }

        on eStorageWriteResp do (resp: (key: int, success: bool, value: int)) {
            var r: (rid: int, key: int, success: bool, value: int);
            announce eMonitorProxyResponseDelivered, (key = resp.key, podId = inflight.podId, isWrite = true);
            r = (rid = inflight.rid, key = resp.key, success = resp.success, value = resp.value);
            send inflight.src, eProxyWriteResp, r;
            hasInflight = false;
            inflight = default(tQElem);
            TryProgress();
        }
    }

    fun TryProgress() {
        var idx: int;
        var pending: int;
        var elem: tQElem;

        if (hasInflight) {
            return;
        }

        pending = sizeof(queue);
        if (pending == 0) {
            return;
        }

        // Non-deterministically either hold requests or forward one
        if ($) {
            announce eMonitorProxyHold, (pending = pending);
            return;
        }

        // Choose a request to forward
        idx = choose(pending);
        elem = queue[idx];
        // Remove from queue
        queue -= (idx);

        // Mark in-flight
        inflight = elem;
        hasInflight = true;

        // Announce forward, then send to storage
        announce eMonitorProxyForward, (key = elem.key, podId = elem.podId, isWrite = elem.isWrite, pending = sizeof(queue));
        if (elem.isWrite) {
            send db, eStorageWrite, (caller = this, key = elem.key, value = elem.value, podId = elem.podId);
        } else {
            send db, eStorageRead, (caller = this, key = elem.key, podId = elem.podId);
        }
    }
}

// CacheNode fronts clients, deduplicates inflight reads, serializes writes per key,
// and routes all storage traffic via StorageProxy. It preserves LSI by always touching
// storage for reads (fromCache = false).
machine CacheNode {
    var proxy: machine;
    var podId: int;

    // Request ID generator
    var nextRid: int;

    // Inflight read deduplication
    var inflightReadByKey: map[int, int];           // key -> rid
    var readWaiters: map[int, set[machine]];        // key -> set[client]
    var pendReadRidToKey: map[int, int];            // rid -> key

    // Per-key write serialization
    var perKeyWriteQueue: map[int, seq[tWriteItem]]; // key -> seq of (client, value)
    var writeInflightKeys: set[int];                 // keys currently with an inflight write
    var pendWriteRidToKey: map[int, int];            // rid -> key
    var pendWriteRidToClient: map[int, machine];     // rid -> client

    // Optional local cache (not used to serve reads to preserve LSI)
    var localCache: map[int, int];

    start state Init {
        entry (p: (proxy: machine, podId: int)) {
            proxy = p.proxy;
            podId = p.podId;

            nextRid = 1;

            inflightReadByKey = default(map[int, int]);
            readWaiters = default(map[int, set[machine]]);
            pendReadRidToKey = default(map[int, int]);

            perKeyWriteQueue = default(map[int, seq[tWriteItem]]);
            writeInflightKeys = default(set[int]);
            pendWriteRidToKey = default(map[int, int]);
            pendWriteRidToClient = default(map[int, machine]);

            localCache = default(map[int, int]);

            goto Ready;
        }
    }

    state Ready {
        on eClientRead do (req: (client: machine, key: int)) {
            var rid: int;
            var s: set[machine];

            if (req.key in inflightReadByKey) {
                // Add to waiters for existing inflight read
                if (req.key in readWaiters) {
                    s = readWaiters[req.key];
                } else {
                    s = default(set[machine]);
                }
                s += (req.client);
                readWaiters[req.key] = s;
                return;
            }

            // Start a new read to proxy
            rid = nextRid;
            nextRid = nextRid + 1;
            inflightReadByKey[req.key] = rid;
            pendReadRidToKey[rid] = req.key;

            s = default(set[machine]);
            s += (req.client);
            readWaiters[req.key] = s;

            // Issue to proxy and announce
            announce eMonitorProxyRequestIssued, (key = req.key, podId = podId, isWrite = false);
            send proxy, eProxyReadReq, (src = this, key = req.key, podId = podId, rid = rid);
        }

        on eClientWrite do (req: (client: machine, key: int, value: int)) {
            var q: seq[tWriteItem];
            var item: tWriteItem;

            if (req.key in perKeyWriteQueue) {
                q = perKeyWriteQueue[req.key];
            } else {
                q = default(seq[tWriteItem]);
            }

            item = (client = req.client, value = req.value);
            q += (sizeof(q), item);
            perKeyWriteQueue[req.key] = q;

            if (!(req.key in writeInflightKeys)) {
                StartNextWrite(req.key);
            }
        }

        on eProxyReadResp do (resp: (rid: int, key: int, value: int)) {
            var s: set[machine];
            var c: machine;

            if (resp.key in readWaiters) {
                s = readWaiters[resp.key];
                foreach (c in s) {
                    // Always fromCache = false to preserve LSI
                    send c, eReadResp, (key = resp.key, value = resp.value, fromCache = false);
                }
                readWaiters -= (resp.key);
            }
            if (resp.key in inflightReadByKey) {
                inflightReadByKey -= (resp.key);
            }
            if (resp.rid in pendReadRidToKey) {
                pendReadRidToKey -= (resp.rid);
            }

            // Update optional local cache with committed value
            localCache[resp.key] = resp.value;
        }

        on eProxyWriteResp do (resp: (rid: int, key: int, success: bool, value: int)) {
            var client: machine;
            var q: seq[tWriteItem];

            if (resp.rid in pendWriteRidToClient) {
                client = pendWriteRidToClient[resp.rid];
                send client, eWriteResp, (key = resp.key, success = resp.success);
                pendWriteRidToClient -= (resp.rid);
            }

            if (resp.rid in pendWriteRidToKey) {
                pendWriteRidToKey -= (resp.rid);
            }

            // Update optional local cache with committed value (if any)
            if (resp.success) {
                localCache[resp.key] = resp.value;
            }

            // Dequeue the completed write and start next if present
            if (resp.key in perKeyWriteQueue) {
                q = perKeyWriteQueue[resp.key];
                if (sizeof(q) > 0) {
                    q -= (0);
                    perKeyWriteQueue[resp.key] = q;
                }
                if (sizeof(q) > 0) {
                    StartNextWrite(resp.key);
                } else {
                    if (resp.key in writeInflightKeys) {
                        writeInflightKeys -= (resp.key);
                    }
                }
            } else {
                if (resp.key in writeInflightKeys) {
                    writeInflightKeys -= (resp.key);
                }
            }
        }
    }

    fun StartNextWrite(k: int) {
        var q: seq[tWriteItem];
        var item: tWriteItem;
        var rid: int;

        if (k in perKeyWriteQueue) {
            q = perKeyWriteQueue[k];
        } else {
            q = default(seq[tWriteItem]);
        }

        if (sizeof(q) == 0) {
            return;
        }

        item = q[0];
        rid = nextRid;
        nextRid = nextRid + 1;

        pendWriteRidToClient[rid] = item.client;
        pendWriteRidToKey[rid] = k;
        writeInflightKeys += (k);

        announce eMonitorProxyRequestIssued, (key = k, podId = podId, isWrite = true);
        send proxy, eProxyWriteReq, (src = this, key = k, value = item.value, podId = podId, rid = rid);
    }
}
